public void nextPermutation(int[] nums) {
    int n = nums.length, k = n - 2, l;
    while(k >= 0 && nums[k] >= nums[k + 1]) k--;

    if(k < 0) {
        Arrays.sort(nums);
    } else {
        for (l = n - 1; l > k; l--) {
            if (nums[l] > nums[k]) break;
        }
        int temp = nums[k];
        nums[k] = nums[l];
        nums[l] = temp;
        Arrays.sort(nums, k + 1, n);
    }
}
```

